const now = new Date();
const today = now.toISOString().slice(0, 10);
return [{
  json: {
    board_id: Number($env.NEXTCLOUD_DECK_BOARD_ID || 1919),
    stack_ids: {
      rueckfrage: 5681,
      vorbereitung: 5684,
      freitagsagenda: 5687,
      todo_laeuft: 5693
    },
    label_ids: {
      review: 7898,
      action_required: 7901,
      information: 7907,
      diskussion: 7910,
      beschluss: 7913,
      sonstiges: 7916
    },
    today,
    generated_at: now.toISOString()
  }
}];

const cfg = $('Set Config').first().json;
const stacks = $input.all().map((item) => item.json || {});
const relevantStackIds = new Set([
  cfg.stack_ids.rueckfrage,
  cfg.stack_ids.vorbereitung,
  cfg.stack_ids.freitagsagenda,
  cfg.stack_ids.todo_laeuft,
]);
function parseDateOnly(value) {
  const text = String(value || '').trim();
  if (!text) return '';
  const match = text.match(/\d{4}-\d{2}-\d{2}/);
  return match ? match[0] : '';
}
function extractField(description, fieldName) {
  const regex = new RegExp('^' + fieldName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\s*:\\s*(.*)$', 'mi');
  const match = String(description || '').match(regex);
  return match ? String(match[1] || '').trim() : '';
}
function parseTodos(description) {
  const lines = String(description || '').split(/\r?\n/);
  const todos = [];
  let current = null;
  let inTodoBlock = false;
  for (const rawLine of lines) {
    const line = rawLine.trimEnd();
    const trimmed = line.trim();
    if (!trimmed && inTodoBlock) continue;
    if (trimmed === 'ToDos') {
      inTodoBlock = true;
      continue;
    }
    if (!inTodoBlock) continue;
    const startMatch = trimmed.match(/^\d+\.\s+Aufgabe:\s*(.+)$/i);
    if (startMatch) {
      if (current) todos.push(current);
      current = { summary: String(startMatch[1] || '').trim(), owner: '', due_date: '', status: '' };
      continue;
    }
    if (!current) {
      if (/^(Technik|Sitzungsnotiz)\s*$/i.test(trimmed)) break;
      continue;
    }
    const ownerMatch = trimmed.match(/^Verantwortlich:\s*(.+)$/i);
    if (ownerMatch) {
      current.owner = String(ownerMatch[1] || '').trim();
      continue;
    }
    const dueMatch = trimmed.match(/^Frist:\s*(.+)$/i);
    if (dueMatch) {
      current.due_date = parseDateOnly(dueMatch[1]);
      continue;
    }
    const statusMatch = trimmed.match(/^Status:\s*(.+)$/i);
    if (statusMatch) {
      current.status = String(statusMatch[1] || '').trim().toLowerCase();
      continue;
    }
    if (/^(Technik|Sitzungsnotiz)\s*$/i.test(trimmed)) break;
  }
  if (current) todos.push(current);
  return todos;
}
function daysDiff(fromDate, toDate) {
  const a = new Date(fromDate + 'T00:00:00Z');
  const b = new Date(toDate + 'T00:00:00Z');
  return Math.round((b - a) / 86400000);
}
const candidates = [];
for (const stack of stacks) {
  const stackId = Number(stack.id || 0);
  if (!relevantStackIds.has(stackId)) continue;
  const cards = Array.isArray(stack.cards) ? stack.cards : [];
  for (const card of cards) {
    const description = String(card.description || '');
    const followupDate = parseDateOnly(extractField(description, 'Wiedervorlage/Frist'));
    const todos = parseTodos(description);
    const openTodosDue = todos.filter((todo) => {
      const status = String(todo.status || '').trim();
      return todo.due_date && status !== 'erledigt' && todo.due_date <= cfg.today;
    });
    const dueReasons = [];
    if (followupDate && followupDate <= cfg.today) {
      dueReasons.push({ type: 'wiedervorlage', due_date: followupDate, overdue_days: daysDiff(followupDate, cfg.today) });
    }
    for (const todo of openTodosDue) {
      dueReasons.push({
        type: 'todo',
        due_date: todo.due_date,
        overdue_days: daysDiff(todo.due_date, cfg.today),
        todo_summary: todo.summary,
        todo_owner: todo.owner,
        todo_status: todo.status || 'offen'
      });
    }
    if (!dueReasons.length) continue;
    const labels = Array.isArray(card.labels) ? card.labels : [];
    const categoryLabel = labels.find((label) => [cfg.label_ids.information, cfg.label_ids.diskussion, cfg.label_ids.beschluss, cfg.label_ids.sonstiges].includes(Number(label.id || 0)));
    candidates.push({
      card_id: Number(card.id || 0),
      title: String(card.title || '').trim() || 'Ohne Titel',
      stack_id: stackId,
      stack_title: String(stack.title || '').trim(),
      category: categoryLabel ? String(categoryLabel.title || '').trim() : extractField(description, 'Kategorie') || 'Sonstiges',
      submitter: extractField(description, 'Einreicher') || 'unbekannt',
      preparation: extractField(description, 'Vorbereitung'),
      followup_date: followupDate,
      labels: labels.map((label) => ({ id: Number(label.id || 0), title: String(label.title || '').trim() })),
      due_reasons: dueReasons,
      todos,
      description
    });
  }
}
return [{ json: { generated_at: cfg.generated_at, today: cfg.today, due_count: candidates.length, candidates } }];

const payload = $input.first().json || {};
const candidates = Array.isArray(payload.candidates) ? payload.candidates : [];
if (!candidates.length) {
  return [{
    json: {
      result: 'no_due_items',
      generated_at: payload.generated_at,
      reminder_markdown: [
        '# AgendaFlow Reminder',
        '',
        `Stand: ${payload.generated_at || new Date().toISOString()}`,
        '',
        'Keine faelligen Wiedervorlagen oder ToDo-Fristen gefunden.'
      ].join('\n')
    }
  }];
}
const lines = [
  '# AgendaFlow Reminder',
  '',
  `Stand: ${payload.generated_at || new Date().toISOString()}`,
  `Faellige Karten: ${candidates.length}`,
  ''
];
candidates.forEach((item, index) => {
  lines.push(`${index + 1}. ${item.title}`);
  lines.push(`   Stack: ${item.stack_title}`);
  lines.push(`   Kategorie: ${item.category}`);
  lines.push(`   Einreicher: ${item.submitter}`);
  if (item.followup_date) {
    lines.push(`   Wiedervorlage/Frist: ${item.followup_date}`);
  }
  if (item.preparation) {
    lines.push(`   Vorbereitung: ${item.preparation}`);
  }
  item.due_reasons.forEach((reason) => {
    if (reason.type === 'wiedervorlage') {
      lines.push(`   Remindergrund: Wiedervorlage faellig seit ${reason.due_date} (${reason.overdue_days} Tage)`);
    } else {
      lines.push(`   Remindergrund: ToDo \"${reason.todo_summary}\" faellig seit ${reason.due_date} (${reason.overdue_days} Tage)`);
      if (reason.todo_owner) {
        lines.push(`   Verantwortlich: ${reason.todo_owner}`);
      }
    }
  });
  lines.push(`   Deck-Card-ID: ${item.card_id}`);
  lines.push('');
});
return [{
  json: {
    result: 'due_items_found',
    generated_at: payload.generated_at,
    due_count: candidates.length,
    candidates,
    reminder_markdown: lines.join('\n')
  }
}];
